import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o,c as r,a as s,b as a,e as t,d as n}from"./app-21664fcf.js";const d={},p=n(`<h1 id="查询截取分析" tabindex="-1"><a class="header-anchor" href="#查询截取分析" aria-hidden="true">#</a> 查询截取分析</h1><p><strong>实际情况问题解决流程</strong></p><ol><li>收到监控系统报告，系统变慢，假如是sql变慢</li><li>开启慢查询日志，设置阙值，比如超过5秒钟的就是慢SQL，并将它抓取出来。</li><li>explain+慢SQL分析</li><li>show profile，查询SQL在Mysql服务器里面的执行细节和生命周期情况</li><li>运维经理 or DBA，进行SQL数据库服务器的参数调优。</li></ol><h2 id="慢查询日志" tabindex="-1"><a class="header-anchor" href="#慢查询日志" aria-hidden="true">#</a> 慢查询日志</h2><h3 id="是什么" tabindex="-1"><a class="header-anchor" href="#是什么" aria-hidden="true">#</a> 是什么</h3><p>MySQL的慢查询日志是MySQL提供的一种日志记录，它用来记录在MySQL中响应时间超过阀值的语句，具体指运行时间超过long_query_time值的SQL，则会被记录到慢查询日志中。</p><p>具体指运行时间超过long_query_time值的SQL，则会被记录到慢查询日志中。long_query_time的默认值为10，意思是运行10秒以上的语句。</p><p>由他来查看哪些SQL超出了我们的最大忍耐时间值，比如一条sql执行超过5秒钟，我们就算慢SQL，希望能收集超过5秒的sql，结合之前explain进行全面分析。</p><h3 id="怎么用" tabindex="-1"><a class="header-anchor" href="#怎么用" aria-hidden="true">#</a> 怎么用</h3><p>默认情况下，MySQL数据库没有开启慢查询日志，需要我们手动来设置这个参数。</p><p>当然，如果不是调优需要的话，<strong>一般不建议启动该参数</strong>，因为开启慢查询日志会或多或少带来一定的性能影响。慢查询日志支持将日志记录写入文件。</p><h4 id="命令行临时修改" tabindex="-1"><a class="header-anchor" href="#命令行临时修改" aria-hidden="true">#</a> 命令行临时修改</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 默认情况下slow_query_log的值为OFF，表示慢查询日志是禁用的</span>
SHOW VARIABLES LIKE <span class="token string">&#39;%slow_query_log%&#39;</span><span class="token punctuation">;</span>
<span class="token comment"># 使用set global slow_query_log=1开启了慢查询日志只对当前数据库生效，如果MySQL重启后则会失效</span>
<span class="token builtin class-name">set</span> global slow_query_log <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>那么开启了慢查询日志后，什么样的SQL才会记录到慢查询日志里面呢？</p><p>这个是由参数long_query_time控制，默认情况下long_query_time的值为10秒，假如运行时间正好等于long_query_time的情况，并不会被记录下来。也就是说，在mysql源码里是判断<strong>大于long_query_time，而非大于等于</strong>。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 查看配置时间</span>
SHOW VARIABLES LIKE <span class="token string">&#39;long_query_time%&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>怎么修改慢查询的标准时间？</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 设置慢的阙值时间</span>
<span class="token builtin class-name">set</span> global <span class="token assign-left variable">long_query_time</span><span class="token operator">=</span><span class="token number">3</span><span class="token punctuation">;</span>
<span class="token comment"># 设置后无效需要重新连接或新开一个会话才能看到修改值。</span>
SHOW VARIABLES LIKE <span class="token string">&#39;long_query_time%&#39;</span><span class="token punctuation">;</span>
<span class="token comment"># 查询当前系统中有多少条慢查询记录</span>
show global variables like<span class="token string">&#39;long_query_time&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="配置文件永久修改" tabindex="-1"><a class="header-anchor" href="#配置文件永久修改" aria-hidden="true">#</a> 配置文件永久修改</h4><p>如果要永久生效，就必须修改配置文件my.cnf（其它系统变量也是如此）</p><p>修改my.cnf文件，<code>[mysqld]</code>下增加或修改参数后，然后重启MySQL服务器。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>slow_query_log <span class="token operator">=</span> <span class="token number">1</span>
slow_query_log_file <span class="token operator">=</span> /var/lib/mysql/query-slow.log
<span class="token comment"># 关于慢查询的参数slow_query_log_file，它指定慢查询日志文件的存放路径，系统默认会给一个缺省的文件host_name-slow.log（如果没有指定参数slow_query_log_file的话）</span>
long_query_time <span class="token operator">=</span> <span class="token number">3</span>
log_output <span class="token operator">=</span> FILE
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="日志分析工具mysqldumpslow" tabindex="-1"><a class="header-anchor" href="#日志分析工具mysqldumpslow" aria-hidden="true">#</a> 日志分析工具mysqldumpslow</h4><p>在生产环境中，如果要手工分析日志，查找、分析SQL，显然是个体力活，MySQL提供了日志分析工具，mysqldumpslow。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 得到返回记录集最多的10个SQL</span>
mysqldumpslow-s r <span class="token parameter variable">-t</span> <span class="token number">10</span> /var/fib/mysql/query-slow.log
<span class="token comment"># 得到访问次数最多的10个SQL</span>
mysqldumpslow-s c <span class="token parameter variable">-t</span> <span class="token number">10</span> /var/lib/mysql/query-slow.log
<span class="token comment"># 得到按照时间排序的前10条里面含有左连接的查询语句</span>
mysqldumpslow-s t <span class="token parameter variable">-t</span> <span class="token number">10</span> <span class="token parameter variable">-g</span> <span class="token string">&quot;left join&quot;</span> /var/lib/mysql/query-slow.log
<span class="token comment"># 另外建议在使用这些命令时结合|和more使用，否则有可能出现爆屏情况</span>
mysqldumpslow-s r <span class="token parameter variable">-t</span> <span class="token number">10</span> /var/lib/mysql/query-slow.log <span class="token operator">|</span> <span class="token function">more</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="show-profile" tabindex="-1"><a class="header-anchor" href="#show-profile" aria-hidden="true">#</a> Show Profile</h2><p>是什么：是mysql提供可以用来分析当前会话中语句执行的资源消耗情况。可以用于SQL的调优的测量</p>`,27),c={href:"http://dev.mysql.com/doc/refman/5.5/en/show-profile.html",target:"_blank",rel:"noopener noreferrer"},u=n(`<p>默认情况下，参数处于关闭状态，并保存最近15次的运行结果</p><h3 id="分析步骤" tabindex="-1"><a class="header-anchor" href="#分析步骤" aria-hidden="true">#</a> 分析步骤</h3><p>是否支持，看看当前的mysql版本是否支持</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>Show variables like <span class="token string">&#39;profiling&#39;</span><span class="token punctuation">;</span>
<span class="token comment"># 默认是关闭，使用前需要开启</span>
Show variables like <span class="token string">&quot;profiling%&quot;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>开启功能，默认是关闭，使用前需要开启</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">set</span> profiling <span class="token operator">=</span> on<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>运行SQL,假如存在运行速度慢的SQL语句</p><div class="language-mysql line-numbers-mode" data-ext="mysql"><pre class="language-mysql"><code>select * from emp group by id%10 limit 150000;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看结果</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>show profiles<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>诊断SQL</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>show profile cpu，block io <span class="token keyword">for</span> query Query_ID<span class="token punctuation">;</span> <span class="token comment"># Query_ID即上一步前面的问题SQL数字号码</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>日常开发需要注意的结论</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 有以下任一情况，说明SQL语句有问题,必须优化</span>
converting HEAP to MyISAM <span class="token comment"># 查询结果太大，内存都不够用了往磁盘上搬了。</span>
Creating tmp table <span class="token comment"># 创建临时表:拷贝数据到临时表,用完再删除</span>
Copying to tmp table on disk <span class="token comment"># 把内存中临时表复制到磁盘，危险！！！</span>
locked
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="全局查询日志" tabindex="-1"><a class="header-anchor" href="#全局查询日志" aria-hidden="true">#</a> 全局查询日志</h2><h3 id="配置启用" tabindex="-1"><a class="header-anchor" href="#配置启用" aria-hidden="true">#</a> 配置启用</h3><p>在mysql的my.cnf中，设置如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#开启</span>
general_log <span class="token operator">=</span> <span class="token number">1</span>
<span class="token comment">#记录日志文件的路径</span>
general_log_file <span class="token operator">=</span> /path/logfile
<span class="token comment">#输出格式</span>
log_output <span class="token operator">=</span> FILE
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="命令启用" tabindex="-1"><a class="header-anchor" href="#命令启用" aria-hidden="true">#</a> 命令启用</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">set</span> global general_log <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
<span class="token builtin class-name">set</span> global log_output <span class="token operator">=</span> <span class="token string">&#39;TABLE&#39;</span><span class="token punctuation">;</span>
<span class="token comment"># 此后，你所编写的sql语句，将会记录到mysql库里的general_log表，可以用下面的命令查看</span>
<span class="token keyword">select</span> * from mysql.general_log<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>会抓取所有的SQL语句,永远不要在生产环境开启这个功能</p></blockquote>`,21);function m(v,b){const e=i("ExternalLinkIcon");return o(),r("div",null,[p,s("p",null,[a("官网： "),s("a",c,[a("http://dev.mysql.com/doc/refman/5.5/en/show-profile.html"),t(e)])]),u])}const k=l(d,[["render",m],["__file","查询截取分析.html.vue"]]);export{k as default};
